function UserCard({ user }) {
  // key is NOT a prop — you can't read it inside here
  return (
    <li>
      <strong>{user.name}</strong> — {user.role}
    </li>
  );
}

function UserList({ users }) {
  return (
    <ul>
      {users.map((user) => (
        <UserCard key={user.id} user={user} />
      ))}
    </ul>
  );
}

